using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));
services.AddChatClient(b => b.UseOpenAIChatClient(modelId, new OpenAI.OpenAIClientOptions
{
    Endpoint = Environment.GetEnvironmentVariable("OPENAI_BASE_URL") is { Length: > 0 } url
        ? new Uri(url)
        : null,
}).Use(new OpenAI.OpenAIClient(apiKey)));

var sp = services.BuildServiceProvider();
var chatClient = sp.GetRequiredService<IChatClient>();
var loggerFactory = sp.GetRequiredService<ILoggerFactory>();

// --- Tools ---
var notebook = new Notebook();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(WebSearch.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// --- Agent ---
var agent = new ChatClientAgent(
    chatClient,
    instructions: """
        You are a research agent. Your workflow:
        1. Break the user's topic into 2-3 focused search queries.
        2. Call web_search for each query to gather information.
        3. As you find important facts, call add_note to record them with source URLs.
        4. After searching, call get_notes to review everything you collected.
        5. Produce a well-structured summary with sections, key findings, and source citations.
        Always cite sources. Be thorough but concise.
        """,
    name: "ResearchAgent",
    description: "Researches topics using web search and note-taking tools",
    tools: tools,
    loggerFactory: loggerFactory);

// --- Run ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔍 Research Agent v1.0         ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.Write("\nEnter a research topic: ");
var topic = Console.ReadLine()?.Trim();

if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n📚 Researching: {topic}\n");

var session = new AgentSession();
var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

await foreach (var update in agent.RunStreamingAsync(topic, session, runOptions))
{
    if (update.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine("\n\n✅ Research complete.");

// === Tool implementations ===

/// <summary>Performs web searches using a search API.</summary>
static class WebSearch
{
    private static readonly HttpClient s_http = new();

    [Description("Search the web for information on a query. Returns a list of results with titles, URLs, and snippets.")]
    public static async Task<string> SearchAsync(
        [Description("The search query")] string query,
        CancellationToken cancellationToken = default)
    {
        Console.WriteLine($"  🌐 Searching: \"{query}\"");

        // Use DuckDuckGo Instant Answer API (no key required)
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

        try
        {
            var response = await s_http.GetFromJsonAsync<JsonElement>(url, cancellationToken);

            var results = new List<string>();

            // Abstract (main answer)
            if (response.TryGetProperty("Abstract", out var abs) && abs.GetString() is { Length: > 0 } abstractText)
            {
                var source = response.TryGetProperty("AbstractURL", out var aUrl) ? aUrl.GetString() : "";
                results.Add($"**Summary**: {abstractText}\nSource: {source}");
            }

            // Related topics
            if (response.TryGetProperty("RelatedTopics", out var topics) && topics.ValueKind == JsonValueKind.Array)
            {
                foreach (var item in topics.EnumerateArray().Take(5))
                {
                    if (item.TryGetProperty("Text", out var text) && text.GetString() is { Length: > 0 } t)
                    {
                        var link = item.TryGetProperty("FirstURL", out var u) ? u.GetString() : "";
                        results.Add($"- {t}\n  URL: {link}");
                    }
                }
            }

            if (results.Count == 0)
            {
                return $"No detailed results found for \"{query}\". Try a more specific query.";
            }

            Console.WriteLine($"  ✅ Found {results.Count} result(s)");
            return string.Join("\n\n", results);
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try rephrasing the query.";
        }
    }
}

/// <summary>Stores research notes collected during the agent session.</summary>
sealed class Notebook
{
    private readonly List<(string Fact, string Source)> _notes = [];

    [Description("Save an important fact or finding to the notebook for later reference. Use this to collect key information as you research.")]
    public string AddNote(
        [Description("The fact or finding to record")] string fact,
        [Description("The source URL or reference")] string source)
    {
        _notes.Add((fact, source));
        Console.WriteLine($"  📝 Note #{_notes.Count} added");
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all notes collected so far. Use this to review findings before writing the final summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes recorded yet.";

        var lines = _notes.Select((n, i) => $"{i + 1}. {n.Fact}\n   Source: {n.Source}");
        Console.WriteLine($"  📋 Returning {_notes.Count} note(s)");
        return string.Join("\n\n", lines);
    }
}

